    const slots = generateAvailableSlots({ date: "[REDACTED_PHONE]", serviceMinutes: 60, hours: mondayHours, appointments: [], blockedDates })
    expect(slots.map((s) => s.start_time)).toEqual(["09:00", "10:30", "15:00"])
