{"content":"-- DepiFlash booking calendar schema
-- Run in Supabase SQL editor or via Management API.

create extension if not exists pgcrypto;

create table if not exists public.appointments (
  id uuid primary key default gen_random_uuid(),
  customer_name text not null,
  customer_phone text not null,
  service_name text not null,
  service_area text not null,
  appointment_date date not null,
  start_time time not null,
  end_time time not null,
  status text not null default 'pending' check (status in ('pending', 'confirmed', 'cancelled', 'completed', 'no_show')),
  notes text not null default '',
  admin_notes text not null default '',
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now()
);

create table if not exists public.blocked_dates (
  id uuid primary key default gen_random_uuid(),
  date date not null,
  start_time time null,
  end_time time null,
  reason text not null default 'Bloqueado',
  block_type text not null default 'full_day' check (block_type in ('full_day', 'partial_day')),
  created_at timestamptz not null default now(),
  constraint partial_block_has_times check (block_type = 'full_day' or (start_time is not null and end_time is not null and start_time < end_time))
);

create table if not exists public.business_hours (
  weekday integer primary key check (weekday between 0 and 6),
  is_open boolean not null default true,
  start_time time not null default '09:00',
  end_time time not null default '17:00',
  slot_minutes integer not null default 60,
  buffer_minutes integer not null default 30,
  updated_at timestamptz not null default now()
);

create table if not exists public.appointment_settings (
  key text primary key,
  value jsonb not null,
  updated_at timestamptz not null default now()
);

insert into public.business_hours (weekday, is_open, start_time, end_time, slot_minutes, buffer_minutes) values
  (0, false, '09:00', '13:00', 60, 30),
  (1, true, '09:00', '17:00', 60, 30),
  (2, true, '09:00', '17:00', 60, 30),
  (3, true, '09:00', '17:00', 60, 30),
  (4, true, '09:00', '17:00', 60, 30),
  (5, true, '09:00', '16:00', 60, 30),
  (6, true, '09:00', '13:00', 60, 30)
on conflict (weekday) do nothing;

insert into public.appointment_settings (key, value) values
  ('booking', '{"service_minutes":60,"default_buffer_minutes":30,"max_days_ahead":45,"min_hours_notice":12}'::jsonb)
on conflict (key) do nothing;

create index if not exists idx_appointments_date_time on public.appointments (appointment_date, start_time);
create index if not exists idx_appointments_status on public.appointments (status);
create index if not exists idx_blocked_dates_date on public.blocked_dates (date);

alter table public.appointments enable row level security;
alter table public.blocked_dates enable row level security;
alter table public.business_hours enable row level security;
alter table public.appointment_settings enable row level security;

-- Public booking inserts may be enabled if you use Supabase directly from browser.
-- Current implementation writes through Next.js API routes, so service_role/server access is preferred.

grant select, insert, update, delete on public.appointments to service_role;
grant select, insert, update, delete on public.blocked_dates to service_role;
grant select, insert, update, delete on public.business_hours to service_role;
grant select, insert, update, delete on public.appointment_settings to service_role;
